### Step 4: Create the LogsActivity trait

Create `app/Traits/LogsActivity.php`:

```php
<?php

namespace App\Traits;

use App\Models\ActivityLog;

trait LogsActivity
{
    public static function bootLogsActivity(): void
    {
        static::created(function ($model) {
            if (! auth()->check()) {
                return;
            }

            ActivityLog::create([
                'loggable_type' => get_class($model),
                'loggable_id'   => $model->id,
                'user_id'       => auth()->id(),
                'event'         => 'created',
                'old_values'    => null,
                'new_values'    => $model->getLoggableAttributeValues(),
                'created_at'    => now(),
            ]);
        });

        static::updating(function ($model) {
            if (! auth()->check()) {
                return;
            }

            $watchedKeys = $model->loggableAttributes ?? [];
            $changedKeys = array_intersect(array_keys($model->getDirty()), $watchedKeys);

            if (empty($changedKeys)) {
                return;
            }

            $oldValues = [];
            $newValues = [];
            foreach ($changedKeys as $key) {
                $oldValues[$key] = $model->getOriginal($key);
                $newValues[$key] = $model->getDirty()[$key];
            }

            ActivityLog::create([
                'loggable_type' => get_class($model),
                'loggable_id'   => $model->id,
                'user_id'       => auth()->id(),
                'event'         => 'updated',
                'old_values'    => $oldValues,
                'new_values'    => $newValues,
                'created_at'    => now(),
            ]);
        });

        static::deleting(function ($model) {
            if (! auth()->check()) {
                return;
            }

            ActivityLog::create([
                'loggable_type' => get_class($model),
                'loggable_id'   => $model->id,
                'user_id'       => auth()->id(),
                'event'         => 'deleted',
                'old_values'    => $model->getLoggableAttributeValues(),
                'new_values'    => null,
                'created_at'    => now(),
            ]);
        });
    }

    protected function getLoggableAttributeValues(): array
    {
        $watchedKeys = $this->loggableAttributes ?? [];
        return collect($this->getAttributes())->only($watchedKeys)->toArray();
    }
}
```

### Step 5: Add trait to Project model

Replace `app/Models/Project.php` entirely with:

```php
<?php

namespace App\Models;

use App\Traits\LogsActivity;
use Illuminate\Database\Eloquent\Model;
use Illuminate\Database\Eloquent\Relations\BelongsTo;
use Illuminate\Database\Eloquent\Relations\HasMany;

class Project extends Model
{
    use LogsActivity;

    protected array $loggableAttributes = ['name', 'description', 'deadline', 'status'];

    protected $fillable = ['user_id', 'name', 'description', 'deadline', 'status'];

    protected $casts = [
        'deadline' => 'date',
    ];

    public function user(): BelongsTo
    {
        return $this->belongsTo(User::class);
    }

    public function tasks(): HasMany
    {
        return $this->hasMany(Task::class);
    }

    public function tags(): HasMany
    {
        return $this->hasMany(Tag::class);
    }

    public function completionPercentage(): int
    {
        $total = $this->tasks()->count();
        if ($total === 0) return 0;
        $done = $this->tasks()->where('status', 'done')->count();
        return (int) round(($done / $total) * 100);
    }
}
```

### Step 6: Add trait to Task model

Replace `app/Models/Task.php` entirely with:

```php
<?php

namespace App\Models;

use App\Traits\LogsActivity;
use Illuminate\Database\Eloquent\Model;
use Illuminate\Database\Eloquent\Relations\BelongsTo;
use Illuminate\Database\Eloquent\Relations\BelongsToMany;
use Illuminate\Database\Eloquent\Relations\HasMany;

class Task extends Model
{
    use LogsActivity;

    protected array $loggableAttributes = ['title', 'description', 'priority', 'status', 'estimated_hours'];

    protected $fillable = [
        'project_id', 'title', 'description', 'priority',
        'status', 'estimated_hours', 'position',
    ];

    public function project(): BelongsTo
    {
        return $this->belongsTo(Project::class);
    }

    public function subtasks(): HasMany
    {
        return $this->hasMany(Subtask::class);
    }

    public function tags(): BelongsToMany
    {
        return $this->belongsToMany(Tag::class, 'task_tag');
    }
}
```

### Step 7: Run tests
```bash
php artisan test --filter=ActivityLogTest
```
Expected: All 7 tests in 'LogsActivity trait' PASS.

### Step 8: Commit
```bash
git add app/Traits/LogsActivity.php app/Models/Project.php app/Models/Task.php tests/Feature/ActivityLogTest.php
git commit -m "feat: add LogsActivity trait and apply to Project and Task models"
```

## Important Notes

- The trait uses `created` (NOT `creating`) Eloquent hook so that `$model->id` is available when the log is created
- The `updating` hook uses `getDirty()` intersected with `$loggableAttributes` — if only `position` changes on a task, `getDirty()` returns `['position' => 99]` but `$loggableAttributes` doesn't include `position`, so `$changedKeys` is empty and no log is written
- `auth()->check()` guard prevents crashes when models are created outside request context (seeders, artisan commands)
- Do NOT add `use LogsActivity` to the `ActivityLog` model itself — this would cause infinite recursion

